module divider (
    input [1:0] dividend,
    input [1:0] denominator,
    output reg [1:0] quotient,
    output reg [1:0] remainder
);
    always @(*) begin
        if (denominator == 2'b00) begin
            quotient = 2'b00;
            remainder = 2'b00;
        end else begin
            quotient = dividend / denominator;
            remainder = dividend % denominator;
        end
    end
endmodule
